// Input: 
// items[0].json.productName -> the product name extracted from size_chart_intent
// items[0].json.raw_rows -> your sheet data with product and size chart columns
const requestedProduct = $('Size Chart').first().json.productName.toLowerCase().trim();
const allProducts = items[0].json.raw_rows;

// Normalize text: remove extra spaces
function normalizeText(text) {
  return text.toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

// Calculate match score based on word overlap and position
function calculateMatchScore(requested, actual) {
  const requestedWords = requested.split(' ');
  const actualWords = actual.split(' ');

  // Check for exact match first
  if (requested === actual) return 0;

  // Check if actual contains all requested words (order doesn't matter)
  const allWordsMatch = requestedWords.every(reqWord => 
    actualWords.some(actWord => actWord.includes(reqWord) || reqWord.includes(actWord))
  );

  if (allWordsMatch) {
    // Bonus: if words appear in same order, score even better
    const inOrder = requestedWords.every((word, idx) => {
      const actIndex = actualWords.findIndex(aw => aw.includes(word) || word.includes(aw));
      return actIndex >= idx;
    });
    return inOrder ? 1 : 2;
  }

  // Count matching words
  const matchingWords = requestedWords.filter(reqWord =>
    actualWords.some(actWord => actWord.includes(reqWord) || reqWord.includes(actWord))
  ).length;

  // Score based on percentage of matching words
  const matchPercentage = matchingWords / requestedWords.length;

  if (matchPercentage >= 0.5) {
    return 10 - (matchPercentage * 10); // Score between 0-5
  }

  // Levenshtein as fallback for typos
  return 50 + levenshtein(requested, actual);
}

// Levenshtein distance function for fuzzy matching
function levenshtein(a, b) {
  const matrix = Array.from({length: b.length + 1}, (_, i) => [i]);
  matrix[0] = Array.from({length: a.length + 1}, (_, j) => j);
  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b[i - 1] === a[j - 1]) matrix[i][j] = matrix[i-1][j-1];
      else matrix[i][j] = Math.min(
        matrix[i-1][j] + 1,
        matrix[i][j-1] + 1,
        matrix[i-1][j-1] + 1
      );
    }
  }
  return matrix[b.length][a.length];
}

// Find closest product match
let bestMatch = null;
let lowestScore = Infinity;

allProducts.forEach(p => {
  const productName = normalizeText(p.product || '');
  const score = calculateMatchScore(requestedProduct, productName);

  console.log(`Comparing "${requestedProduct}" with "${productName}" - Score: ${score}`);

  if (score < lowestScore) {
    lowestScore = score;
    bestMatch = p;
  }
});

// Accept matches with reasonable scores
// Score 0-10 = good match (exact or partial word match)
// Score > 10 = weak match, reject
if (lowestScore > 10) {
  bestMatch = null;
}

return [
  {
    json: {
      chatid: $input.first().json.chat_id,
      productName: requestedProduct,
      matchedProduct: bestMatch ? bestMatch.product : null,
      sizeChart: bestMatch && bestMatch['Size Chart'] ? bestMatch['Size Chart'] : 'Size information not available',
      matchScore: lowestScore,
      debugInfo: `Requested: "${requestedProduct}" | Matched: "${bestMatch ? bestMatch.product : 'none'}" | Score: ${lowestScore}`
    }
  }
];

