const text = $input.first().json.body.Message|| "";

// Normalize
const t = text.trim();

// 1) Detect Arabic script (easy & accurate)
const hasArabic = /[\u0600-\u06FF]/.test(t);

// 2) Detect Arabizi: contains numbers + letters in a typical Arabizi pattern
const hasArabizi = /[a-zA-Z]+[2357]/i.test(t) || /[2357][a-zA-Z]/i.test(t);

// Output language
let language = "english";

if (hasArabic) {
  language = "arabic";
} else if (hasArabizi) {
  language = "english"; // You decided Arabizi should be treated as English
}

return [
  {
    json: {
      detected_language: language
    }
  }
];

// Code node to extract message
