// Convert Google Drive sharing URL to direct image URL
const sizeChartUrl = $input.item.json.sizeChart;

function convertGoogleDriveUrl(url) {
  if (!url || url === 'Size information not available') {
    return null;
  }

  // Handle different Google Drive URL formats
  let fileId = null;

  // Format 1: https://drive.google.com/file/d/FILE_ID/view
  if (url.includes('drive.google.com/file/d/')) {
    fileId = url.split('/d/')[1].split('/')[0];
  }
  // Format 2: https://drive.google.com/open?id=FILE_ID
  else if (url.includes('drive.google.com/open?id=')) {
    fileId = url.split('id=')[1].split('&')[0];
  }
  // Format 3: https://drive.google.com/uc?id=FILE_ID
  else if (url.includes('drive.google.com/uc?id=')) {
    fileId = url.split('id=')[1].split('&')[0];
  }

  if (!fileId) {
    console.log('Could not extract file ID from URL:', url);
    return null;
  }

  // Return direct download/view URL
  return `https://drive.google.com/uc?export=view&id=${fileId}`;
}

const directImageUrl = convertGoogleDriveUrl(sizeChartUrl);

return {
  json: {
    ...($input.item.json),
    directImageUrl: directImageUrl,
    originalUrl: sizeChartUrl,
    chatid: $input.first().json.chatid
  }
};

// Extract message from JSON or pass through if already a string
// For n8n Code node

const input = $input.first().json.output;

let message;

try {
  // Check if input is already a string
  if (typeof input === 'string') {
    // Try to parse it as JSON
    try {
      const parsed = JSON.parse(input);
      // If it has a message field, extract it
      message = parsed.message || input;
    } catch {
      // Not valid JSON, use as is
      message = input;
    }
  } 
  // If input is an object
  else if (typeof input === 'object' && input !== null) {
    // Check if it has a message property
    if (input.message) {
      message = input.message;
    } else {
      // If no message field, stringify the whole object
      message = JSON.stringify(input);
    }
  } 
  // For other types, convert to string
  else {
    message = String(input);
  }
} catch (error) {
  // Fallback: use input as is
  message = input;
}

return { 
  json: { 
    message: message 
  } 
};

